--=============================================-- Developer:	Kolapo -- Create date: 18-02-2026-- Description:	This code is to create the Store procedure-- Revise Date: 18-02-2026 -- Version:		v1.0-- =============================================Create Procedure spLoansAmountAs BeginSelect * From [dbo].[LoansAccounts]End--How to run stored procedureExec spLoansAmount--How to modify/alter store procedureCreate or Alter Procedure spLoansAmount@AccNo int null, @Installments intAs BeginSelect * From [dbo].[LoansAccounts]Where AccNo = @AccNoAnd Installments = @Installments End-- How to run a parameterized store procedureExec spLoansAmount 5, 36--Write a store procedure using encounter table --Create parameters using EncounterClass Field Create Procedure spEncounterClassAs BeginSelect * From [dbo].[encounters]End--How to run stored procedureExec spEncounterClassSelect *From [dbo].[encounters]Create or Alter Procedure spEncounterClass@ENCOUNTERCLASS varchar(50) As BeginSelect * From [dbo].[encounters]Where ENCOUNTERCLASS = @ENCOUNTERCLASSEnd-- How to run a parameterized store procedureExec spEncounterClass 'Emergency'--Write a store procedure using encounter table --Create parameters using EncounterClass Field Create Procedure spEncounterClassAs BeginSelect * From [dbo].[encounters]End--How to run stored procedureExec spEncounterClassSelect *From [dbo].[encounters]Create or Alter Procedure spEncounterClass@ENCOUNTERCLASS varchar(50) ,@Description varchar (max)As BeginSelect * From [dbo].[encounters]Where ENCOUNTERCLASS = @ENCOUNTERCLASSAnd [DESCRIPTION] = @DescriptionEnd-- How to run a parameterized store procedurespEncounterClass 'Emergency' , 'Emergency Room Admission'